function s(t){if(!t)return null;const n=t.split(":").map(Number);return n.some(isNaN)?null:n.length===3?n[0]*3600+n[1]*60+n[2]:n.length===2?n[0]*60+n[1]:null}function a(t){return s(t)}function c(t){const n=s(t);return n===null?1/0:n}function l(t){if(t==null||!isFinite(t))return"—";const n=Math.round(t),r=Math.floor(n/3600),o=Math.floor(n%3600/60),u=n%60,i=String(o).padStart(2,"0"),e=String(u).padStart(2,"0");return r>0?`${r}:${i}:${e}`:`${o}:${e}`}export{c as a,l as f,a as p};
